# Perl Script: Haversine Distance Calculator

This script calculates the distance between two locations using the Haversine formula. It accepts latitude and longitude inputs, handles errors, and provides output in kilometers or miles.

---

## 📌 Script: `haversine_distance.pl`

```perl
#!/usr/bin/perl
use strict;
use warnings;
use Getopt::Long;
use LWP::Simple;
use JSON;

# Script: haversine_distance.pl
# Author: [Your Name]
# Date: [Date]

# This script calculates the distance between two locations using the Haversine formula.
# It supports kilometers and miles output and includes error handling.

# Configuration
my $OUTPUT_UNITS = 'km';  # Default output unit
my $LOCATION_NAMES = 0;   # 1 for output location names, 0 for only distance

# Parse command-line options
GetOptions(
    'unit=<' => \$OUTPUT_UNITS,
    'names' => \$LOCATION_NAMES,
) or die "Usage: $0 -u <km|mi> -n";

# Error handling
if (!defined $OUTPUT_UNITS) {
    die "Missing required option: -u (unit)\n";
}

# Function to get location name from coordinates
sub get_location_name {
    my ($lat, $lon) = @_;
    my $url = "https://api.openweathermap.org/geo/1.0/latlng.php?lat=$lat&lon=$lon&limit=1";
    my $response = get($url);
    my $data = JSON::decode($response);
    return $data->{'name'} if $data && $data->{'name'};
    return "Unknown";
}

# Function to calculate distance using Haversine formula
sub haversine_distance {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $R = 6371;  # Radius of Earth in kilometers

    my $dlat = deg2rad($lat2 - $lat1);
    my $dlong = deg2rad($lon2 - $lon1);

    my $a = sin($dlat/2) ** 2 + cos(rad2deg($lat1)) * cos(rad2deg($lat2)) * sin($dlong/2) ** 2;
    my $c = 2 * atan2(sqrt($a), sqrt(1 - $a));
    my $distance = $R * $c;

    return $distance;
}

# Main function
sub main {
    my ($lat1, $lon1, $lat2, $lon2) = @_;
    my $distance = haversine_distance($lat1, $lon1, $lat2, $lon2);

    # Get location names
    my $loc1_name = get_location_name($lat1, $lon1);
    my $loc2_name = get_location_name($lat2, $lon2);

    # Output
    if ($LOCATION_NAMES) {
        print "Distance between $loc1_name and $loc2_name: \n";
    } else {
        print "Distance between the two locations: \n";
    }

    print "Distance: $distance km\n" if $OUTPUT_UNITS eq 'km';
    print "Distance: $distance mi\n" if $OUTPUT_UNITS eq 'mi';
}

# Main execution
my ($lat1, $lon1, $lat2, $lon2);
my ($unit, $names);

# Parse command-line arguments
my $usage = "Usage: $0 -u <km|mi> -n";
GetOptions(
    'u=<' => \$unit,
    'n' => \$names,
) or die $usage;

# Check if inputs are provided
if (!defined $lat1 || !defined $lon1 || !defined $lat2 || !defined $lon2) {
    die "Please provide latitude and longitude for both locations.\n";
}

# Calculate and output distance
main($lat1, $lon1, $lat2, $lon2);
