use strict;
use warnings;

# Function to merge two sorted arrays into one sorted array in descending order
sub merge {
    my ($arr1, $arr2) = @_;
    my @merged;

    # Base case: if one array is empty, return the other
    return grep { $_ } @$arr1 if !@$arr2;
    return grep { $_ } @$arr2 if !@$arr1;

    # Merge the two arrays while maintaining descending order
    while (scalar @$arr1 && scalar @$arr2) {
        if ($arr1->[0] >= $arr2->[0]) {
            push @merged, $arr1->[0];
            shift @$arr1;
        } else {
            push @merged, $arr2->[0];
            shift @$arr2;
        }
    }

    # Add remaining elements from either array
    push @merged, @$arr1;
    push @merged, @$arr2;

    return @merged;
}

# Function to perform merge sort on an array
sub merge_sort {
    my ($arr) = @_;
    return $arr if @$arr <= 1;

    # Split the array into two halves
    my $mid = int(@$arr / 2);
    my $left = merge_sort($arr->[0..$mid - 1]);
    my $right = merge_sort($arr->[$mid..$#arr]);

    # Merge the two sorted halves
    return merge($left, $right);
}

# Main program
