    print "Enter integers separated by spaces (end with 'exit'):\n";

    my @arr;
    while (1) {
        my $input = <STDIN>;
        chomp $input;

        if ($input eq 'exit') {
            last;
        }

        # Check if input is valid
        if (!m/^-?\d+$/ && $input !~ /^exit$/) {
